class Solution {
public:
    int numberOfWays(int n, int x) {
        const int MOD = 1'000'000'007;
        vector<int> bases;
        for (int i = 1; ; ++i) {
            long long val = 1;
            for (int j = 0; j < x; ++j) {
                val *= i;
                if (val > n) break;
            }
            if (val > n) break;
            bases.push_back((int)val);
        }
        int m = bases.size();
        vector<int> dp(n + 1, 0);
        dp[0] = 1;
        for (int i = 0; i < m; ++i) {
            int b = bases[i];
            for (int j = n; j >= b; --j) {
                dp[j] = (dp[j] + dp[j - b]) % MOD;
            }
        }
        return dp[n];
    }
};
```
